module eeprom_cell(  
    input wire [4:0] data_in,  
    input wire write_enable,  
    output reg [4:0] data_out  
);  

    reg [4:0] obf_stored_value;  

    always @(*) begin  
        if (write_enable) begin  
            obf_stored_value = data_in;  
        end  
        data_out = obf_stored_value;  
    end  
endmodule
